#include<bits/stdc++.h>
using namespace std;
int n,m,dp[2000010],u[2000010],v[2000010];
struct node
{
    int x,y,ty,id;
    bool operator<(const node&b)const
    {
        return(x<b.x||(x==b.x&&y<b.y));
    }
}a[2000010];
int y[2000010],tot;
int bit[2000010];
int lowbit(int x)
{
    return x&-x;
}
int query(int x)
{
    int ans=0;
    for(int i=x;i>=1;i-=lowbit(i))
    {
        ans=min(ans,bit[i]);
    }
    return ans;
}
void update(int x,int v)
{
    for(int i=x;i<=m*2;i+=lowbit(i))
    {
        bit[i]=min(bit[i],v);
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d%d%d",&a[i].x,&a[i].y,&a[i+m].x,&a[i+m].y);
        y[++tot]=a[i].y;
        y[++tot]=a[i+m].y;
        a[i].id=a[i+m].id=i;
    }
    sort(a+1,a+1+(m*2));
    sort(y+1,y+1+tot);
    tot=unique(y+1,y+1+tot)-y-1;
    for(int i=1;i<=m*2;i++)
    {
        a[i].ty=lower_bound(y+1,y+1+tot,a[i].y)-y;
        if(u[a[i].id])
        {
            v[a[i].id]=i;
        }
        else
        {
            u[a[i].id]=i;
        }
    }
    int ans=0;
    for(int i=1;i<=m*2;i++)
    {
        dp[i]=min(dp[i],query(a[i].ty));
        if(u[a[i].id]==i)
        {
            dp[v[a[i].id]]=min(dp[v[a[i].id]],dp[i]+a[i].x+a[i].y-a[v[a[i].id]].x-a[v[a[i].id]].y);
        }
        update(a[i].ty,dp[i]);
        ans=min(ans,dp[i]);
    }
    printf("%d",n*2+ans);
    return 0;
}
